import React from "react";
import { useCart } from "./CartContext";
import { useNavigate } from "react-router-dom";
import "./App.css";

function CartPage() {
  const { cart, increaseQty, decreaseQty } = useCart();
  const navigate = useNavigate();

  const totalItems = cart.reduce((sum, i) => sum + i.quantity, 0);

  const totalPrice = cart.reduce(
    (sum, i) => sum + (i.price || 20) * i.quantity,
    0
  );

  return (
    <div className="page">

      {/* HEADER */}
      <div className="help-topbar">
        <h2>Your Cart</h2>

        <button onClick={() => navigate("/help")}>
          ⬅ Back
        </button>
      </div>

      {/* EMPTY CART */}
      {cart.length === 0 ? (
        <div style={{ padding: "20px" }}>
          <h3>Your cart is empty 🛒</h3>
        </div>
      ) : (
        <>
          {/* ITEMS */}
          <div className="medicine-section">
            <div className="medicine-grid">

              {cart.map((item) => (
                <div className="medicine-card" key={item.name}>
                  <h3>{item.name}</h3>

                  <div className="qty-controls">
                    <button onClick={() => decreaseQty(item.name)}>
                      ➖
                    </button>

                    <span>{item.quantity}</span>

                    <button
                      onClick={() => increaseQty(item.name)}
                      disabled={item.quantity >= 5}
                    >
                      ➕
                    </button>
                  </div>

                  <p>₹ {(item.price || 20) * item.quantity}</p>
                </div>
              ))}

            </div>
          </div>

          {/* SUMMARY */}
          <div style={{ padding: "20px" }}>
            <h3>Total Items: {totalItems}</h3>
            <h2>Total Price: ₹ {totalPrice}</h2>

            <button
              style={{
                marginTop: "10px",
                padding: "10px 20px",
                background: "green",
                color: "white",
                border: "none",
                cursor: "pointer"
              }}
              onClick={() => alert("Proceed to backend checkout 🚀")}
            >
              Proceed to Buy
            </button>
          </div>
        </>
      )}
    </div>
  );
}

export default CartPage;
